import re
class Solution:
    def numDifferentIntegers(self, word):
        runs = []
        cur = ''
        for ch in word:
            if ch.isdigit():
                cur += ch
            else:
                if cur:
                    runs.append(cur)
                    cur = ''
        if cur:
            runs.append(cur)
        norm = set()
        for r in runs:
            t = r.lstrip('0')
            if t == '':
                t = '0'
            norm.add(t)
        return len(norm)

