class Solution:
    def numDifferentIntegers(self, word):
        seen = set()
        i = 0
        n = len(word)
        while i < n:
            if word[i].isdigit():
                j = i
                while j < n and word[j].isdigit():
                    j += 1
                t = word[i:j].lstrip('0')
                seen.add(t if t else '0')
                i = j
            else:
                i += 1
        return len(seen)

