var numDifferentIntegers = function(word) {
    const seen = new Set();
    const n = word.length;
    let i = 0;
    const isDigit = c => c >= '0' && c <= '9';
    while (i < n) {
        if (isDigit(word[i])) {
            let j = i;
            while (j < n && isDigit(word[j])) j++;
            let t = word.slice(i, j).replace(/^0+/, '');
            seen.add(t === '' ? '0' : t);
            i = j;
        } else {
            i++;
        }
    }
    return seen.size;
};
